internal fun IrValue.codeBlock(): CodeBlock {
  return when (this) {
    is IrBooleanValue -> CodeBlock.of("%L", value)
    // Enums are serialized to JSON String
    is IrEnumValue -> CodeBlock.of("%S", value)
    is IrIntValue -> {
      val asInt = value.toIntOrNull()
      if (asInt != null) {
        // The value fits in kotlin Int
        CodeBlock.of("%L", value)
      } else {
        CodeBlock.of("%T(%S)", KotlinSymbols.JsonNumber, value)
      }
    }

    is IrFloatValue -> {
      val asDouble = value.toDoubleOrNull()
      if (asDouble != null) {
        // The value fits in a kotlin Double
        CodeBlock.of("%L", value)
      } else {
        CodeBlock.of("%T(%S)", KotlinSymbols.JsonNumber, value)
      }
    }

    is IrListValue -> codeBlock()
    IrNullValue -> CodeBlock.of("null")
    is IrObjectValue -> codeBlock()
    is IrStringValue -> CodeBlock.of("%S", value)
    is IrVariableValue -> CodeBlock.of("%T(%S)", KotlinSymbols.CompiledVariable, name)
  }
}

internal fun resolveIrType(type: IrType, jsExport: Boolean, isInterface: Boolean = false): TypeName {
  return when {
    type.optional -> {
      KotlinSymbols.Optional.parameterizedBy(resolveIrType(type.optional(false), jsExport, isInterface))
    }

    type.catchTo != IrCatchTo.NoCatch -> {
      resolveIrType(type.catchTo(IrCatchTo.NoCatch), jsExport, isInterface).let {
        when (type.catchTo) {
          IrCatchTo.Null -> it.copy(nullable = true)
          IrCatchTo.Result -> KotlinSymbols.FieldResult.parameterizedBy(it)
          IrCatchTo.NoCatch -> error("") // keep the compiler happy
        }
      }
    }

    type.nullable -> {
      resolveIrType(type.nullable(false), jsExport, isInterface).copy(nullable = true)
    }

    else -> {
      when (type) {
        is IrListType -> resolveIrType(type.ofType, jsExport, isInterface).wrapInList(jsExport, isInterface)
        is IrModelType -> resolveAndAssert(ResolverKeyKind.Model, type.path)
        is IrEnumType -> if (jsExport) {
          KotlinSymbols.String
        } else {
          resolveAndAssert(ResolverKeyKind.SchemaType, type.name)
        }
        is IrScalarType -> resolveScalarTarget(type.name)

        is IrNamedType -> resolveSchemaType(type.name)
      }
    }
  }
}

internal fun wrapInlineClass(expression: CodeBlock, type: IrType): CodeBlock {
  val inlineClassProperty = resolveScalarInlineProperty(type.rawType().name)

  return buildCodeBlock {
    when (type) {
      is IrListType -> {
        if (inlineClassProperty != null) {
          add(expression)
          if (type.nullable) {
            add("?")
          }
          add(".map { %L }", wrapInlineClass(CodeBlock.of("it"), type.ofType))
        } else {
          add(expression)
        }
      }

      is IrScalarType -> {
        if (inlineClassProperty == null) {
          add(expression)
        } else {
          val targetName = resolveScalarTarget(type.name)
          when {
            type.nullable -> add("%L?.let { %T(it) }", expression, targetName)
            else -> add("%T(%L)", targetName, expression)
          }
        }
      }

      else -> {
        add(expression)
      }
    }
  }
}

override fun dumpTo(collector: SerializersModuleCollector) {
    class2ContextualFactory.forEach { (kclass, serial) ->
        when (serial) {
            is ContextualProvider.Argless -> collector.contextual(
                kclass as KClass<Any>,
                serial.serializer as KSerializer<Any>
            )
            is ContextualProvider.WithTypeArguments -> collector.contextual(kclass, serial.provider)
        }
    }

    polyBase2Serializers.forEach { (baseClass, classMap) ->
        classMap.forEach { (actualClass, serializer) ->
            collector.polymorphic(
                baseClass as KClass<Any>,
                actualClass as KClass<Any>,
                serializer.cast()
            )
        }
    }

    polyBase2DefaultSerializerProvider.forEach { (baseClass, provider) ->
        collector.polymorphicDefaultSerializer(baseClass as KClass<Any>, provider as (PolymorphicSerializerProvider<Any>))
    }

    polyBase2DefaultDeserializerProvider.forEach { (baseClass, provider) ->
        collector.polymorphicDefaultDeserializer(baseClass as KClass<Any>, provider as (PolymorphicDeserializerProvider<Any>))
    }
}

internal inline fun Buffer.commonIndexOf(b: Byte, fromIndex: Long, toIndex: Long): Long {
  var fromIndex = fromIndex
  var toIndex = toIndex
  require(fromIndex in 0..toIndex) { "size=$size fromIndex=$fromIndex toIndex=$toIndex" }

  if (toIndex > size) toIndex = size
  if (fromIndex == toIndex) return -1L

  seek(fromIndex) { s, offset ->
    var s = s ?: return -1L
    var offset = offset

    // Scan through the segments, searching for b.
    while (offset < toIndex) {
      val data = s.data
      val limit = minOf(s.limit.toLong(), s.pos + toIndex - offset).toInt()
      var pos = (s.pos + fromIndex - offset).toInt()
      while (pos < limit) {
        if (data[pos] == b) {
          return pos - s.pos + offset
        }
        pos++
      }

      // Not in this segment. Try the next one.
      offset += (s.limit - s.pos).toLong()
      fromIndex = offset
      s = s.next!!
    }

    return -1L
  }
}

@JvmName("-array")
inline fun <reified T> Adapter<T>.array() = object : Adapter<Array<T>> {

  private inline fun <reified T> arrayFromJson(
      wrappedAdapter: Adapter<T>,
      reader: JsonReader,
      customScalarAdapters: CustomScalarAdapters,
  ): Array<T> {
    reader.beginArray()
    val list = mutableListOf<T>()
    while (reader.hasNext()) {
      list.add(wrappedAdapter.fromJson(reader, customScalarAdapters))
    }
    reader.endArray()
    return list.toTypedArray()
  }

  private inline fun <reified T> arrayToJson(
      wrappedAdapter: Adapter<T>,
      writer: JsonWriter,
      customScalarAdapters: CustomScalarAdapters,
      value: Array<T>,
  ) {
    writer.beginArray()
    value.forEach {
      wrappedAdapter.toJson(writer, customScalarAdapters, it)
    }
    writer.endArray()
  }

  override fun fromJson(reader: JsonReader, customScalarAdapters: CustomScalarAdapters): Array<T> {
    return arrayFromJson(this@array, reader, customScalarAdapters)
  }

  override fun toJson(writer: JsonWriter, customScalarAdapters: CustomScalarAdapters, value: Array<T>) {
    return arrayToJson(this@array, writer, customScalarAdapters, value)
  }
}

@Suppress("UNCHECKED_CAST")
private fun JsonReader.readError(): Error {
  var message = ""
  var locations: List<Error.Location>? = null
  var path: List<Any>? = null
  var extensions: Map<String, Any?>? = null
  var nonStandardFields: MutableMap<String, Any?>? = null
  beginObject()
  while (hasNext()) {
    when (val name = nextName()) {
      "message" -> message = nextString() ?: ""
      "locations" -> {
        locations = readErrorLocations()
      }

      "path" -> {
        path = readPath()
      }

      "extensions" -> {
        extensions = readAny() as? Map<String, Any?>?
      }

      else -> {
        if (!ignoreUnknownKeys()) {
          throw JsonDataException("Unknown key '$name' found at path: '${getPath().joinToString(".")}'")
        }

        if (nonStandardFields == null) nonStandardFields = mutableMapOf()
        nonStandardFields[name] = readAny()
      }
    }
  }
  endObject()


  @Suppress("DEPRECATION")
  return Error.Builder(message = message).locations(locations).path(path).extensions(extensions).nonStandardFields(nonStandardFields)
      .build()
}

override fun nextDouble(): Double {
  val p = peekIfNone()
  when {
    p == PEEKED_LONG -> {
      peeked = PEEKED_NONE
      pathIndices[stackSize - 1]++
      return peekedLong.toDouble()
    }
    p == PEEKED_NUMBER -> {
      peekedString = buffer.readUtf8(peekedNumberLength.toLong())
    }
    p == PEEKED_DOUBLE_QUOTED -> {
      peekedString = nextQuotedValue(DOUBLE_QUOTE_OR_SLASH)
    }
    p == PEEKED_SINGLE_QUOTED -> {
      peekedString = nextQuotedValue(SINGLE_QUOTE_OR_SLASH)
    }
    p == PEEKED_UNQUOTED -> {
      peekedString = nextUnquotedValue()
    }
    p != PEEKED_BUFFERED -> throw JsonDataException("Expected a double but was ${peek()} at path ${getPathAsString()}")
  }

  peeked = PEEKED_BUFFERED

  val result = try {
    peekedString!!.toDouble()
  } catch (e: NumberFormatException) {
    throw JsonDataException("Expected a double but was $peekedString at path ${getPathAsString()}")
  }

  if (result.isNaN() || result.isInfinite()) {
    throw JsonEncodingException("JSON forbids NaN and infinities: $result at path ${getPathAsString()}")
  }

  peekedString = null
  peeked = PEEKED_NONE
  pathIndices[stackSize - 1]++
  return result
}

override fun skipValue() {
  var count = 0
  do {
    when (peekIfNone()) {
      PEEKED_BEGIN_ARRAY -> {
        push(JsonScope.EMPTY_ARRAY)
        count++
      }
      PEEKED_BEGIN_OBJECT -> {
        push(JsonScope.EMPTY_OBJECT)
        count++
      }
      PEEKED_END_ARRAY -> {
        stackSize--
        count--
      }
      PEEKED_END_OBJECT -> {
        stackSize--
        count--
      }
      PEEKED_UNQUOTED_NAME, PEEKED_UNQUOTED -> {
        skipUnquotedValue()
      }
      PEEKED_DOUBLE_QUOTED, PEEKED_DOUBLE_QUOTED_NAME -> {
        skipQuotedValue(DOUBLE_QUOTE_OR_SLASH)
      }
      PEEKED_SINGLE_QUOTED, PEEKED_SINGLE_QUOTED_NAME -> {
        skipQuotedValue(SINGLE_QUOTE_OR_SLASH)
      }
      PEEKED_NUMBER -> {
        buffer.skip(peekedNumberLength.toLong())
      }
    }
    peeked = PEEKED_NONE
  } while (count != 0)
  pathIndices[stackSize - 1]++
  pathNames[stackSize - 1] = "null"
}

private fun List<GQLSelection>.detectCycles(
    globallyVisitedFragments: MutableSet<String>,
    locallyVisitedFragments: MutableSet<String>,
    path: List<String>,
) {
  forEach {
    when (it) {
      is GQLField -> {
        it.selections.detectCycles(globallyVisitedFragments, locallyVisitedFragments, path + it.responseName())
      }

      is GQLInlineFragment -> {
        it.selections.detectCycles(globallyVisitedFragments, locallyVisitedFragments, path + "__on${it.typeCondition?.name ?: ""}")
      }

      is GQLFragmentSpread -> {
        val fragment = fragmentDefinitions.get(it.name)
        if (fragment != null) {
          val name = fragment.name
          val index = path.indexOf("__${name}")
          val nextPath = path + "__${fragment.name}"
          if (index != -1) {
            issues.add(FragmentCycle("Fragment '$name' spreads itself, creating a cycle at '${nextPath.subList(index, nextPath.size).joinToString(".")}'", it.sourceLocation))
            cyclicFragments.add(name)
            return@forEach
          }

          fragment.detectCycles(globallyVisitedFragments, locallyVisitedFragments, nextPath)
        }
      }
    }
  }
}

private fun areValuesEqual(valueA: GQLValue, valueB: GQLValue): Boolean {
  return when (valueA) {
    is GQLIntValue -> (valueB as? GQLIntValue)?.value == valueA.value
    is GQLFloatValue -> (valueB as? GQLFloatValue)?.value == valueA.value
    is GQLStringValue -> (valueB as? GQLStringValue)?.value == valueA.value
    is GQLBooleanValue -> (valueB as? GQLBooleanValue)?.value == valueA.value
    is GQLEnumValue -> (valueB as? GQLEnumValue)?.value == valueA.value
    is GQLNullValue -> valueB is GQLNullValue
    is GQLListValue -> {
      if (valueB !is GQLListValue) {
        return false
      }

      for (i in 0.until(valueA.values.size)) {
        if (!areValuesEqual(valueA.values[i], valueB.values[i])) {
          return false
        }
      }
      true
    }

    is GQLObjectValue -> {
      if (valueB !is GQLObjectValue) {
        return false
      }

      (valueA.fields + valueB.fields).groupBy { it.name }.values.forEach {
        if (it.size != 2) {
          return false
        }
        if (!areValuesEqual(it[0].value, it[1].value)) {
          return false
        }
      }
      true
    }

    is GQLVariableValue -> (valueB as? GQLVariableValue)?.name == valueA.name
  }
}

private fun ValidationScope.validateAndCoerceScalar(value: GQLValue, expectedType: GQLNamedType): GQLValue {
  return when (expectedType.name) {
    "Int" -> {
      if (value !is GQLIntValue) {
        registerIssue(value, expectedType)
      }
      value
    }

    "Float" -> {
      when (value) {
        is GQLFloatValue -> value
        // Int get coerced to floats
        is GQLIntValue -> GQLFloatValue(value = value.value)
        else -> {
          registerIssue(value, expectedType)
          value
        }
      }
    }

    "String" -> {
      if (value !is GQLStringValue) {
        registerIssue(value, expectedType)
      }
      value
    }

    "Boolean" -> {
      if (value !is GQLBooleanValue) {
        registerIssue(value, expectedType)
      }
      value
    }

    "ID" -> {
      // 3.5.5 ID can be either string or int
      if (value !is GQLStringValue && value !is GQLIntValue) {
        registerIssue(value, expectedType)
      }
      value
    }

    else -> {
      registerIssue(value, expectedType)
      value
    }
  }
}

private fun readUnicodeEscape(): Int {
  if (pos == len) {
    throw LexerException("Unterminated Unicode escape", pos, line, column(pos), null)
  }

  when (src[pos]) {
    '{' -> {
      pos++
      return readVariableUnicodeEscape()
    }

    else -> {
      val c1 = readFixedUnicodeEscape()

      if (c1.isUnicodeScalar()) {
        return c1
      }

      val start = pos - 6

      // GraphQL allows JSON-style surrogate pair escape sequences, but only when
      // a valid pair is formed.

      if (c1.isLeadingSurrogate()) {
        if (pos + 1 < len
            && src[pos] == '\\'
            && src[pos + 1] == 'u') {
          pos += 2
          val c2 = readFixedUnicodeEscape()
          if (c2.isTrailingSurrogate()) {
            return codePoint(c1, c2)
          }
        }
      }

      throw LexerException("Invalid Unicode escape '${src.substring(start, pos)}'", start, line, column(start), null)
    }
  }
}

override fun visitClassOrObject(classOrObject: KtClassOrObject) {
    super.visitClassOrObject(classOrObject)

    val classMembers = classOrObject.body?.children?.filterNot { it is KtClassOrObject } ?: return

    analyze(classOrObject) {
        val allProperties = classMembers.filterIsInstance<KtProperty>().mapNotNull {
            val name = it.name ?: return@mapNotNull null
            val callableId = it.symbol.callableId ?: return@mapNotNull null
            name to callableId
        }.toMap()

        val declaredProperties = mutableSetOf<CallableId>()

        classMembers.forEach { member ->
            member.forEachDescendantOfType<KtNameReferenceExpression> {
                val property = allProperties[it.text]
                if (property != null &&
                    property !in declaredProperties &&
                    property == it.resolveToCall()?.successfulVariableAccessCall()?.symbol?.callableId
                ) {
                    report(Finding(Entity.from(it), "'${it.text}' is used before declaration."))
                }
            }
            if (member is KtProperty) {
                declaredProperties.addIfNotNull(allProperties[member.name])
            }
        }
    }
}

private fun List<KtWhenCondition>.evaluateSubjectWhenExpression(
    expression: KtWhenExpression,
    subjectDescriptors: List<KaVariableSymbol>,
) {
    var isNonNullChecked = false
    var isNullChecked = false
    forEach { whenCondition ->
        when (whenCondition) {
            is KtWhenConditionWithExpression -> {
                if (whenCondition.expression?.text == "null") {
                    isNullChecked = true
                }
            }

            is KtWhenConditionIsPattern -> {
                if (isNullableCheck(whenCondition.typeReference, whenCondition.isNegated)) {
                    isNullChecked = true
                } else {
                    isNonNullChecked = true
                }
            }
        }
    }
    if (expression.elseExpression.isValidElseExpression()) {
        if (isNullChecked) {
            isNonNullChecked = true
        } else if (isNonNullChecked) {
            isNullChecked = true
        }
    }
    subjectDescriptors.forEach { callableDescriptor ->
        nullableParams[callableDescriptor]?.let {
            if (isNullChecked) it.isNullChecked = true
            if (isNonNullChecked) it.isNonNullChecked = true
        }
    }
}

private fun createDeploymentBundle(modules: List<ModuleToUpload>): InputProvider {
    val zipFile = project.buildDir.resolve("publishing/compose-deploy.zip")
    zipFile.parentFile.mkdirs()

    ZipOutputStream(FileOutputStream(zipFile)).use { zipOut ->
        val sourcesToDestinations = modules.map { it.localDir to it.mavenDirectory() }
        val addedEntries = mutableSetOf<String>()

        for ((sourceDir, destDir) in sourcesToDestinations) {
            val files = sourceDir.listFiles() ?: continue

            for (file in files) {
                val entryPath = "$destDir/${file.name}"
                if (file.isFile && !addedEntries.contains(entryPath)) {
                    addedEntries.add(entryPath)
                    val entry = ZipEntry(entryPath)
                    zipOut.putNextEntry(entry)
                    file.inputStream().use { input ->
                        input.copyTo(zipOut)
                    }
                    zipOut.closeEntry()
                }
            }
        }
    }

    logger.info("Zip bundle is created at $zipFile")

    return InputProvider(zipFile.length()) {
        FileInputStream(zipFile).asInput()
    }
}

private fun Element.parseColorStops(): Array<Pair<Float, Color>> {
    val items = childrenSequence
        .filterIsInstance<Element>()
        .filter { it.nodeName == "item" }
        .toList()

    val colorStops = items.mapIndexedNotNullTo(mutableListOf()) { index, item ->
        item.parseColorStop(defaultOffset = index.toFloat() / items.lastIndex.coerceAtLeast(1))
    }

    if (colorStops.isEmpty()) {
        val startColor = attributeOrNull(ANDROID_NS, "startColor")?.let(::parseColorValue)
        val centerColor = attributeOrNull(ANDROID_NS, "centerColor")?.let(::parseColorValue)
        val endColor = attributeOrNull(ANDROID_NS, "endColor")?.let(::parseColorValue)

        if (startColor != null) {
            colorStops.add(0f to Color(startColor))
        }
        if (centerColor != null) {
            colorStops.add(0.5f to Color(centerColor))
        }
        if (endColor != null) {
            colorStops.add(1f to Color(endColor))
        }
    }

    return colorStops.toTypedArray()
}

public fun parseAuthorizationHeader(headerValue: String): HttpAuthHeader? {
    var index = 0
    index = headerValue.skipSpaces(index)

    val tokenStartIndex = index
    while (index < headerValue.length && headerValue[index].isToken()) {
        index++
    }

    // Auth scheme
    val authScheme = headerValue.substring(tokenStartIndex until index)
    index = headerValue.skipSpaces(index)

    if (authScheme.isBlank()) {
        return null
    }

    if (headerValue.length == index) {
        return HttpAuthHeader.Parameterized(authScheme, emptyList())
    }

    val token68EndIndex = matchToken68(headerValue, index)
    val token68 = headerValue.substring(index until token68EndIndex).trim()
    if (token68.isNotEmpty()) {
        if (token68EndIndex == headerValue.length) {
            return HttpAuthHeader.Single(authScheme, token68)
        }
    }

    val parameters = mutableMapOf<String, String>()
    val endIndex = matchParameters(headerValue, index, parameters)
    return if (endIndex == -1) {
        HttpAuthHeader.Parameterized(authScheme, parameters)
    } else {
        throw ParseException("Function parseAuthorizationHeader can parse only one header")
    }
}

public fun digestAuthChallenge(
    realm: String,
    nonce: String = generateNonceBlocking(),
    domain: List<String> = emptyList(),
    opaque: String? = null,
    stale: Boolean? = null,
    algorithm: DigestAlgorithm = DigestAlgorithm.SHA_256,
    charset: Charset? = null,
    userhash: Boolean = false,
    qop: List<String> = emptyList()
): Parameterized = Parameterized(
    authScheme = AuthScheme.Digest,
    parameters = linkedMapOf<String, String>().apply {
        put("realm", realm.quote())
        put("nonce", nonce.quote())
        if (domain.isNotEmpty()) {
            put("domain", domain.joinToString(" ").quote())
        }
        if (opaque != null) {
            put("opaque", opaque.quote())
        }
        if (stale != null) {
            put("stale", stale.toString())
        }
        put("algorithm", algorithm.name)
        if (charset != null) {
            put("charset", charset.name.toUpperCasePreservingASCIIRules())
        }
        if (userhash) {
            put("userhash", "true")
        }
        if (qop.isNotEmpty()) {
            put("qop", qop.joinToString(",").quote())
        }
    },
    encoding = HeaderValueEncoding.QUOTED_WHEN_REQUIRED
)

public fun match(pattern: ContentType): Boolean {
    if (pattern.contentType != "*" && !pattern.contentType.equals(contentType, ignoreCase = true)) {
        return false
    }

    if (pattern.contentSubtype != "*" && !pattern.contentSubtype.equals(contentSubtype, ignoreCase = true)) {
        return false
    }

    for ((patternName, patternValue) in pattern.parameters) {
        val matches = when (patternName) {
            "*" -> {
                when (patternValue) {
                    "*" -> true
                    else -> parameters.any { p -> p.value.equals(patternValue, ignoreCase = true) }
                }
            }

            else -> {
                val value = parameter(patternName)
                when (patternValue) {
                    "*" -> value != null
                    else -> value.equals(patternValue, ignoreCase = true)
                }
            }
        }

        if (!matches) {
            return false
        }
    }
    return true
}

private fun parseHeaderValueParameter(text: String, start: Int, parameters: Lazy<ArrayList<HeaderValueParam>>): Int {
    fun addParam(text: String, start: Int, end: Int, value: String) {
        val name = text.subtrim(start, end)
        if (name.isEmpty()) {
            return
        }

        parameters.value.add(HeaderValueParam(name, value))
    }

    var position = start
    while (position <= text.lastIndex) {
        when (text[position]) {
            '=' -> {
                val (paramEnd, paramValue) = parseHeaderValueParameterValue(text, position + 1)
                addParam(text, start, position, paramValue)
                return paramEnd
            }

            ';', ',' -> {
                addParam(text, start, position, "")
                return position
            }

            else -> position++
        }
    }

    addParam(text, start, position, "")
    return position
}

internal fun Sink.writeTLSClientHello(
    version: TLSVersion,
    suites: List<CipherSuite>,
    random: ByteArray,
    sessionId: ByteArray,
    serverName: String? = null
) {
    writeShort(version.code.toShort())
    writeFully(random)

    val sessionIdLength = sessionId.size
    if (sessionIdLength < 0 || sessionIdLength > 0xff || sessionIdLength > sessionId.size) {
        throw TLSException("Illegal sessionIdLength")
    }

    writeByte(sessionIdLength.toByte())
    writeFully(sessionId, 0, sessionIdLength)

    writeShort((suites.size * 2).toShort())
    for (suite in suites) {
        writeShort(suite.code)
    }

    // compression is always null
    writeByte(1)
    writeByte(0)

    val extensions = ArrayList<Source>()
    extensions += buildSignatureAlgorithmsExtension()
    extensions += buildECCurvesExtension()
    extensions += buildECPointFormatExtension()

    serverName?.let { name ->
        extensions += buildServerNameExtension(name)
    }

    writeShort(extensions.sumOf { it.remaining.toInt() }.toShort())
    for (e in extensions) {
        writePacket(e)
    }
}

private suspend fun sendClientCertificate(info: CertificateInfo): CertificateAndKey? {
    val chainAndKey = config.certificates.find { candidate ->
        val leaf = candidate.certificateChain.first()

        val validAlgorithm = when (leaf.publicKey.algorithm) {
            "RSA" -> info.types.contains(CertificateType.RSA)
            "DSS" -> info.types.contains(CertificateType.DSS)
            else -> false
        }

        if (!validAlgorithm) return@find false

        val hasHashAndSignInCommon = info.hashAndSign.none {
            it.name.equals(leaf.sigAlgName, ignoreCase = true)
        }

        if (hasHashAndSignInCommon) return@find false

        info.authorities.isEmpty() ||
            candidate.certificateChain
                .map { X500Principal(it.issuerX500Principal.name) }
                .any { it in info.authorities }
    }

    sendHandshakeRecord(TLSHandshakeType.Certificate) {
        writeTLSCertificates(chainAndKey?.certificateChain ?: emptyArray())
    }

    return chainAndKey
}

internal fun IrValue.codeBlock(): CodeBlock {
  return when (this) {
    is IrObjectValue -> codeBlock()
    is IrListValue -> codeBlock()
    // Enums are serialized to JSON String
    is IrEnumValue -> CodeBlock.of(S, value)
    is IrIntValue -> {
      val asInt = value.toIntOrNull()
      if (asInt != null) {
        // The value fits in kotlin Int
        CodeBlock.of(L, value)
      } else {
        CodeBlock.of("new $T($S)", JavaClassNames.JsonNumber, value)
      }
    }

    is IrFloatValue -> {
      val asDouble = value.toDoubleOrNull()
      if (asDouble != null) {
        // The value fits in a kotlin Double
        CodeBlock.of(L, value)
      } else {
        CodeBlock.of("new $T($S)", JavaClassNames.JsonNumber, value)
      }
    }

    is IrBooleanValue -> CodeBlock.of(L, value)
    is IrStringValue -> CodeBlock.of(S, value)
    is IrVariableValue -> CodeBlock.of("new $T($S)", JavaClassNames.CompiledVariable, name)
    is IrNullValue -> CodeBlock.of("null")
  }
}

override fun selectName(names: List<String>): Int {
  if (names.isEmpty()) {
    return -1
  }

  while (hasNext()) {
    val name = nextName()
    val expectedIndex = indexStack[indexStackSize - 1]
    if (names[expectedIndex] == name) {
      return expectedIndex.also {
        indexStack[indexStackSize - 1] = expectedIndex + 1
        if (indexStack[indexStackSize - 1] == names.size) {
          indexStack[indexStackSize - 1] = 0
        }
      }
    } else {
      // guess failed, fallback to full search
      var index = expectedIndex
      while (true) {
        index++
        if (index == names.size) {
          index = 0
        }
        if (index == expectedIndex) {
          break
        }
        if (names[index] == name) {
          return index.also {
            indexStack[indexStackSize - 1] = index + 1
            if (indexStack[indexStackSize - 1] == names.size) {
              indexStack[indexStackSize - 1] = 0
            }
          }
        }
      }

      if (!ignoreUnknownKeys) {
        throw JsonDataException("Unknown key '$name' found at path: '${getPathAsString()}'")
      }
      skipValue()
    }
  }
  return -1
}

private fun <T : Any> String.parseInternal(filePath: String?, options: ParserOptions, block: Parser.() -> T): GQLResult<T> {
  return try {
    GQLResult(Parser(this, options, filePath).block(), emptyList())
  } catch (e: ParserException) {
    GQLResult(
        null,
        listOf(
            ParsingError(
                e.message,
                SourceLocation(
                    start = e.token.start,
                    end = e.token.end,
                    line = e.token.line,
                    column = e.token.column,
                    filePath = filePath
                )
            )
        )
    )
  } catch (e: LexerException) {
    GQLResult(
        null,
        listOf(
            ParsingError(
                e.message,
                SourceLocation(
                    start = e.pos,
                    end = e.pos + 1,
                    line = e.line,
                    column = e.column,
                    filePath = filePath
                )
            )
        )
    )
  }
}

fun toGQLDocument(filePath: String?): GQLDocument {
  return with(introspectionSchema.__schema) {
    val directives = if (directives is Optional.Absent) {
      println("Apollo: __schema.directives is missing, double check your introspection query")
      emptyList()
    } else {
      directives.getOrThrow()
    }

    GQLDocument(
        definitions = types.map {
          when (it.kind) {
            RTypeKind.SCALAR -> it.toGQLScalarTypeDefinition()
            RTypeKind.OBJECT -> it.toGQLObjectTypeDefinition()
            RTypeKind.INTERFACE -> it.toGQLInterfaceTypeDefinition()
            RTypeKind.UNION -> it.toGQLUnionTypeDefinition()
            RTypeKind.ENUM -> it.toGQLEnumTypeDefinition()
            RTypeKind.INPUT_OBJECT -> it.toGQLInputObjectTypeDefinition()
            else -> throw ConversionException("Unknown type kind: ${it.kind}")
          }
        }
            + directives.mapNotNull { it.toGQLDirectiveDefinition() }
            + schemaDefinition()
            + (introspectionSchema.__service.getOrNull()?.toGQLServiceDefinition() ?: defaultServiceDefinition()),
        sourceLocation = SourceLocation.forPath(filePath)
    )
  }
}

private suspend fun onFrame(status: WinHttpWebSocketStatus, readBuffer: ByteArray) {
    when (status.bufferType) {
        WinHttpWebSocketBuffer.BinaryMessage -> {
            val data = readBuffer.copyOf(status.size)
            _incoming.send(Frame.Binary(fin = true, data = data))
        }

        WinHttpWebSocketBuffer.BinaryFragment -> {
            val data = readBuffer.copyOf(status.size)
            _incoming.send(Frame.Binary(fin = false, data = data))
        }

        WinHttpWebSocketBuffer.TextMessage -> {
            val data = readBuffer.copyOf(status.size)
            _incoming.send(Frame.Text(fin = true, data = data))
        }

        WinHttpWebSocketBuffer.TextFragment -> {
            val data = readBuffer.copyOf(status.size)
            _incoming.send(Frame.Text(fin = false, data = data))
        }

        WinHttpWebSocketBuffer.Close -> {
            val data = readBuffer.copyOf(status.size)
            _incoming.send(Frame.Close(data))
        }
    }
}

private suspend fun sendNextFrame() {
    val frame = _outgoing.receive()

    when (frame.frameType) {
        FrameType.TEXT -> {
            val type = if (frame.fin) {
                WINHTTP_WEB_SOCKET_UTF8_MESSAGE_BUFFER_TYPE
            } else {
                WINHTTP_WEB_SOCKET_UTF8_FRAGMENT_BUFFER_TYPE
            }
            frame.data.usePinned { src ->
                sendFrame(type, src)
            }
        }

        FrameType.BINARY,
        FrameType.PING,
        FrameType.PONG -> {
            val type = if (frame.fin) {
                WINHTTP_WEB_SOCKET_BINARY_MESSAGE_BUFFER_TYPE
            } else {
                WINHTTP_WEB_SOCKET_BINARY_FRAGMENT_BUFFER_TYPE
            }
            frame.data.usePinned { src ->
                sendFrame(type, src)
            }
        }

        FrameType.CLOSE -> {
            val data = buildPacket { writeFully(frame.data) }
            val code = data.readShort().toInt()
            val reason = data.readText()
            sendClose(code, reason)
            socketJob.complete()
        }
    }
}

internal fun Grammar.printDebug(offset: Int = 0): Unit = when (this) {
    is StringGrammar -> printlnWithOffset(offset, "STRING[${Regex.escape(value)}]")
    is RawGrammar -> printlnWithOffset(offset, "STRING[$value]")
    is NamedGrammar -> {
        printlnWithOffset(offset, "NAMED[$name]")
        grammar.printDebug(offset + 2)
    }
    is SequenceGrammar -> {
        printlnWithOffset(offset, "SEQUENCE")
        grammars.forEach { it.printDebug(offset + 2) }
    }
    is OrGrammar -> {
        printlnWithOffset(offset, "OR")
        grammars.forEach { it.printDebug(offset + 2) }
    }
    is MaybeGrammar -> {
        printlnWithOffset(offset, "MAYBE")
        grammar.printDebug(offset + 2)
    }
    is ManyGrammar -> {
        printlnWithOffset(offset, "MANY")
        grammar.printDebug(offset + 2)
    }
    is AtLeastOne -> {
        printlnWithOffset(offset, "MANY_NOT_EMPTY")
        grammar.printDebug(offset + 2)
    }
    is AnyOfGrammar -> printlnWithOffset(offset, "ANY_OF[${Regex.escape(value)}]")
    is RangeGrammar -> printlnWithOffset(offset, "RANGE[$from-$to]")
}

public fun generateCertificate(
    file: File? = null,
    algorithm: String = "SHA1withRSA",
    keyAlias: String = "mykey",
    keyPassword: String = "changeit",
    jksPassword: String = keyPassword,
    keySizeInBits: Int = 1024,
    keyType: KeyType = KeyType.Server
): KeyStore {
    val keyStore = buildKeyStore {
        certificate(keyAlias) {
            val (hashName, signName) = algorithm.split("with")
            this.hash = HashAlgorithm.valueOf(hashName)
            this.sign = SignatureAlgorithm.valueOf(signName)
            this.password = keyPassword
            this.keySizeInBits = keySizeInBits
            this.keyType = keyType
            this.subject = if (keyType == KeyType.CA) DEFAULT_CA_PRINCIPAL else DEFAULT_PRINCIPAL
            this.domains = listOf("127.0.0.1", "localhost")
        }
    }

    // for backwards-compatibility, we also register the certificate under this Cert-suffixed alias
    keyStore.setCertificateEntry(keyAlias + "Cert", keyStore.getCertificate(keyAlias))

    file?.let {
        keyStore.saveToFile(it, jksPassword)
    }
    return keyStore
}

private fun typeSpec(): TypeSpec {
  return if (withFields) {
    TypeSpec
        .classBuilder(simpleName)
        .primaryConstructor(
            FunSpec.constructorBuilder()
                .addParameter(
                    ParameterSpec.builder(
                        __fields,
                        KotlinSymbols.MapOfStringToNullableAny
                    ).build()
                )
                .build()
        )
        .superclass(KotlinSymbols.DataMap)
        .addSuperclassConstructorParameter(__fields)
        .addSuperinterfaces(dataBuilder.superTypes.map {
          ClassName(packageName, dataMapName(it, false, layout))
        })
        .apply {
          if (dataBuilder.isAbstract) {
            addSuperinterface(
                ClassName(packageName, dataMapName(dataBuilder.name, false, layout))
            )
          }
        }
        .build()
  } else {
    TypeSpec
        .interfaceBuilder(simpleName)
        .addSuperinterfaces(dataBuilder.superTypes.map {
          ClassName(packageName, dataMapName(it, false, layout))
        })
        .build()
  }
}

internal fun ByteArray.encodeBase64(
  includePadding: Boolean,
  map: ByteArray = BASE64,
): String {
  val length = if (includePadding) {
    (size + 2) / 3 * 4
  } else {
    (size * 4 + 2) / 3
  }
  val out = ByteArray(length)
  var index = 0
  val end = size - size % 3
  var i = 0
  while (i < end) {
    val b0 = this[i++].toInt()
    val b1 = this[i++].toInt()
    val b2 = this[i++].toInt()
    out[index++] = map[(b0 and 0xff shr 2)]
    out[index++] = map[(b0 and 0x03 shl 4) or (b1 and 0xff shr 4)]
    out[index++] = map[(b1 and 0x0f shl 2) or (b2 and 0xff shr 6)]
    out[index++] = map[(b2 and 0x3f)]
  }
  when (size - end) {
    1 -> {
      val b0 = this[i].toInt()
      out[index++] = map[b0 and 0xff shr 2]
      out[index++] = map[b0 and 0x03 shl 4]
      if (includePadding) {
        out[index++] = '='.code.toByte()
        out[index] = '='.code.toByte()
      }
    }
    2 -> {
      val b0 = this[i++].toInt()
      val b1 = this[i].toInt()
      out[index++] = map[(b0 and 0xff shr 2)]
      out[index++] = map[(b0 and 0x03 shl 4) or (b1 and 0xff shr 4)]
      out[index++] = map[(b1 and 0x0f shl 2)]
      if (includePadding) {
        out[index] = '='.code.toByte()
      }
    }
  }
  return out.toUtf8String()
}

private fun readEscapeCharacter(): Char {
  if (!source.request(1)) throwSyntaxError("Unterminated escape sequence")

  return when (val escaped = buffer.readByte().toInt().toChar()) {
    'u' -> {
      if (!source.request(4)) {
        throw EOFException("Unterminated escape sequence at path " + getPath())
      }
      // Equivalent to Integer.parseInt(stringPool.get(buffer, pos, 4), 16);
      var result = 0.toChar()
      var i = 0
      val end = i + 4
      while (i < end) {
        val c = buffer[i.toLong()]
        result = (result.code shl 4).toChar()
        result += when {
          c >= '0'.code.toByte() && c <= '9'.code.toByte() -> (c - '0'.code.toByte())
          c >= 'a'.code.toByte() && c <= 'f'.code.toByte() -> (c - 'a'.code.toByte() + 10)
          c >= 'A'.code.toByte() && c <= 'F'.code.toByte() -> (c - 'A'.code.toByte() + 10)
          else -> throwSyntaxError("\\u" + buffer.readUtf8(4))
        }
        i++
      }
      buffer.skip(4)
      result
    }
    't' -> '\t'
    'b' -> '\b'
    'n' -> '\n'
    'r' -> '\r'
    'f' -> '\u000C'
    '\n', '\'', '"', '\\', '/' -> escaped
    else -> {
      throwSyntaxError("Invalid escape sequence: \\$escaped")
    }
  }
}

internal fun parseColorValue(color: String): Int {
    require(color.startsWith("#")) { "Invalid color value $color" }

    return when (color.length) {
        7 -> {
            // #RRGGBB
            color.substring(1).toUInt(16).toInt() or ALPHA_MASK
        }
        9 -> {
            // #AARRGGBB
            color.substring(1).toUInt(16).toInt()
        }
        4 -> {
            // #RGB
            val v = color.substring(1).toUInt(16).toInt()
            var k = (v shr 8 and 0xF) * 0x110000
            k = k or (v shr 4 and 0xF) * 0x1100
            k = k or (v and 0xF) * 0x11
            k or ALPHA_MASK
        }
        5 -> {
            // #ARGB
            val v = color.substring(1).toUInt(16).toInt()
            var k = (v shr 12 and 0xF) * 0x11000000
            k = k or (v shr 8 and 0xF) * 0x110000
            k = k or (v shr 4 and 0xF) * 0x1100
            k = k or (v and 0xF) * 0x11
            k or ALPHA_MASK
        }
        else -> ALPHA_MASK
    }
}

private fun funSpec(): FunSpec {
  return FunSpec.builder("adaptToJson")
      .addParameter("value", KotlinSymbols.Any)
      .returns(KotlinSymbols.Any)
      .receiver(KotlinSymbols.FakeResolverContext)
      .addCode(
          buildCodeBlock {
            add("val writer = %T()\n", KotlinSymbols.MapJsonWriter)
            add("when(mergedField.type.rawType().name){\n")
            withIndent {
              scalars.forEach {
                if (context.resolver.resolve(ResolverKey(ResolverKeyKind.SchemaType, it)) != null) {
                  val initializer = context.resolver.adapterInitializer(IrScalarType(it), false, jsExport = false)
                  val scalarTarget = context.resolver.resolveScalarTarget(it)
                  if (scalarTarget != KotlinSymbols.Any) {
                    add("%S -> %L.toJson(writer, customScalarAdapters, value as %T)\n", it, initializer, scalarTarget)
                  } else {
                    add("%S -> %L.toJson(writer, customScalarAdapters, value)\n", it, initializer)
                  }
                }
              }
              add("else -> return value\n")
            }
            add("}\n")
            add("return writer.root()!!\n")
          }
      )
      .build()
}

